#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 30

int grid[MAX][MAX];
int n;

void printSolution(int *solution, int k) {
    printf("%d\n", k);
    for (int i = 0; i < k; i++) {
        printf("%d %d\n", solution[i * 2], solution[i * 2 + 1]);
    }
}

void toggleLight(int x, int y) {
    if (x < 0 || x >= n || y < 0 || y >= n) return;
    grid[x][y] = 1 - grid[x][y];
}

int isSolved() {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (grid[i][j] == 1) return 0;
        }
    }
    return 1;
}

void solve(int *solution, int k) {
    if (isSolved()) {
        printSolution(solution, k);
        return;
    }
    if (k > n * n) return;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            solution[k * 2] = i + 1;
            solution[k * 2 + 1] = j + 1;
            toggleLight(i, j);
            toggleLight(i - 1, j);
            toggleLight(i + 1, j);
            toggleLight(i, j - 1);
            toggleLight(i, j + 1);
            solve(solution, k + 1);
            toggleLight(i, j);
            toggleLight(i - 1, j);
            toggleLight(i + 1, j);
            toggleLight(i, j - 1);
            toggleLight(i, j + 1);
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        scanf("%d", &n);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                char c;
                scanf(" %c", &c);
                grid[i][j] = c - '0';
            }
        }
        int solution[n * n * 2];
        solve(solution, 0);
    }
    return 0;
}

